	"net/http"
	"strings"
)

type FailureReason string

const (
	ReasonMethodNotAllowed       FailureReason = "METHOD_NOT_ALLOWED"
	ReasonInvalidRequest         FailureReason = "INVALID_REQUEST"
	ReasonInvalidToken           FailureReason = "INVALID_TOKEN"
	ReasonAuthorizationDenied    FailureReason = "AUTHORIZATION_DENIED"
	ReasonPasswordChangeRequired FailureReason = "PASSWORD_CHANGE_REQUIRED"
	ReasonNotFound               FailureReason = "NOT_FOUND"
	ReasonUserNotFound           FailureReason = "USER_NOT_FOUND"
	ReasonMarketNotFound         FailureReason = "MARKET_NOT_FOUND"

	ReasonValidationFailed    FailureReason = "VALIDATION_FAILED"
	ReasonMarketClosed        FailureReason = "MARKET_CLOSED"
	ReasonInsufficientBalance FailureReason = "INSUFFICIENT_BALANCE"
	ReasonNoPosition          FailureReason = "NO_POSITION"
	ReasonInsufficientShares  FailureReason = "INSUFFICIENT_SHARES"
	ReasonDustCapExceeded     FailureReason = "DUST_CAP_EXCEEDED"
	ReasonInternalError       FailureReason = "INTERNAL_ERROR"
)

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

// AuthFailureReason maps auth-layer HTTP outcomes to the shared public reason
// vocabulary used by touched envelope handlers.
func AuthFailureReason(statusCode int, message string) FailureReason {
	switch {
	case statusCode >= http.StatusInternalServerError:
		return ReasonInternalError
	case statusCode == http.StatusUnauthorized:
		return ReasonInvalidToken
	case statusCode == http.StatusForbidden && strings.EqualFold(message, "Password change required"):
		return ReasonPasswordChangeRequired
	case statusCode == http.StatusForbidden:
		return ReasonAuthorizationDenied
	case statusCode == http.StatusNotFound:
		return ReasonUserNotFound
	case statusCode == http.StatusBadRequest:
		return ReasonValidationFailed
	default:
		return ReasonInternalError
	}
}

func IsValidationMessage(message string) bool {
	lower := strings.ToLower(message)
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required")
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}

package handlers

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestWriteResult(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteResult(recorder, http.StatusCreated, map[string]int{"value": 7})
	if err != nil {
		t.Fatalf("WriteResult returned error: %v", err)
	}

	if recorder.Code != http.StatusCreated {
		t.Fatalf("expected status 201, got %d", recorder.Code)
	}

	if contentType := recorder.Header().Get("Content-Type"); contentType != "application/json" {
		t.Fatalf("expected application/json content type, got %q", contentType)
	}

	var response SuccessEnvelope[map[string]int]
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if !response.OK {
		t.Fatalf("expected ok=true, got false")
	}

	if response.Result["value"] != 7 {
		t.Fatalf("expected result value 7, got %d", response.Result["value"])
	}
}

func TestWriteBusinessFailure(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteBusinessFailure(recorder, ReasonValidationFailed)
	if err != nil {
		t.Fatalf("WriteBusinessFailure returned error: %v", err)
	}

	if recorder.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", recorder.Code)
	}

	var response FailureEnvelope
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if response.OK {
		t.Fatalf("expected ok=false, got true")
	}

	if response.Reason != string(ReasonValidationFailed) {
		t.Fatalf("expected reason %q, got %q", ReasonValidationFailed, response.Reason)
	}
}

func TestAuthFailureReason(t *testing.T) {
	tests := []struct {
		name       string
		statusCode int
		message    string
		want       FailureReason
	}{
		{"missing token", http.StatusUnauthorized, "Authorization header is required", ReasonInvalidToken},
		{"password change required", http.StatusForbidden, "Password change required", ReasonPasswordChangeRequired},
		{"authorization denied", http.StatusForbidden, "admin privileges required", ReasonAuthorizationDenied},
		{"user not found", http.StatusNotFound, "User not found", ReasonUserNotFound},
		{"internal", http.StatusInternalServerError, "Failed to load user", ReasonInternalError},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := AuthFailureReason(tt.statusCode, tt.message); got != tt.want {
				t.Fatalf("expected %q, got %q", tt.want, got)
			}
		})
	}
}

func TestIsValidationMessage(t *testing.T) {
	if !IsValidationMessage("display name must be between 1 and 50 characters") {
		t.Fatalf("expected validation phrase to match")
	}
	if IsValidationMessage("database connection string leaked") {
		t.Fatalf("expected internal error phrase not to match")
	}
}

